import{_ as a,o,c as t,ag as n}from"./chunks/framework.DmWB24NN.js";const r="/sonata-books-mockup.png",g=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","pageClass":"home-background","hero":{"name":"<img src=\\"/logo-white.png\\" class=\\"hero-logo\\" alt=\\"Sonata - Swords & Darkness\\">","text":"Core Rules & World Bible","tagline":"The complete guide to the campaign setting","actions":[{"theme":"brand","text":"Core Rules","link":"/Book I - Core Rules/B01 - Chapter 00 - Introduction"},{"theme":"alt","text":"The Known World","link":"/Book II - The Known World/B02 - Chapter 00_ Introduction"}]}},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),s={name:"index.md"};function i(l,e,d,h,c,m){return o(),t("div",null,[...e[0]||(e[0]=[n('<div class="hero-extra-text"><h2 id="heroic-fantasy-grim-peril" tabindex="-1">Heroic Fantasy &amp; Grim Peril <a class="header-anchor" href="#heroic-fantasy-grim-peril" aria-label="Permalink to &quot;Heroic Fantasy &amp; Grim Peril&quot;">​</a></h2><h3 id="a-retroclone-of-the-most-famous-role-playing-game-s-second-edition" tabindex="-1">A retroclone of the most famous role-playing game’s second edition. <a class="header-anchor" href="#a-retroclone-of-the-most-famous-role-playing-game-s-second-edition" aria-label="Permalink to &quot;A retroclone of the most famous role-playing game’s second edition.&quot;">​</a></h3><p>You&#39;re an adventurer. You may even be the son of a noble, but you are not legitimate. So you go beyond the boundaries of civilization, in pursuit of ancient secrets — exploring ruins, braving monsters&#39; lairs, carving out a name for yourself and your company.</p><p>Whatever the courts and the castles have to offer, none of it was ever going to be yours — not as Human, not as Aelár born without a homeland to inherit, not as Vartran carrying a name the Church of Tar&#39;amaan already hates on principle. Something always closes the door first. What&#39;s left is the road: contracts, ruins, and monster lairs, worked because the alternative was disappearing quietly where nobody would notice.</p><p><strong><em>Sonata - Swords &amp; Darkness</em></strong> is a dark fantasy retroclone of the most famous role-playing game&#39;s second edition, built on the <em>For Gold &amp; Glory&#39;s</em> foundation and set entirely inside the Known World. Death is real, resources are finite, and mercenary work exists in the first place because civilization has already failed enough people to keep the trade in business.</p><p>Nine ancestries are open to play, human included, and a class is a trade learned, not a destiny handed down. Warriors train as Fighter, Paladin, Ranger, or Champion. Wizards work as Mage or Sorcerer. Priests serve as Cleric or Druid — though only Húldar and Aelár may walk the Druid&#39;s path; anyone else who tries is hunted as a thief by the Hyerophancy&#39;s own agents. Rogues run Thief or Bard. Ten classes, nine ancestries, and every combination has its own reason for being out here instead of somewhere safer.</p><p>What there is to do hasn&#39;t changed since the first table sat down to play: dungeons cleared, wilderness crossed, downtime spent between jobs — hirelings retained, wounds mended, coin banked or burned. The difference is what it can add up to. The Vithurian Orchestra turns notable deeds into songs, and nobody starts eligible for one; a company earns that attention the same hard way they earned everything else. Agents investigate. Reports get filed. And somewhere down the road, the same court that never opened its doors might finally have a reason to remember your name.</p><h3 id="this-game-is-free-and-it-will-stay-free" tabindex="-1">This game is free, and it will stay free <a class="header-anchor" href="#this-game-is-free-and-it-will-stay-free" aria-label="Permalink to &quot;This game is free, and it will stay free&quot;">​</a></h3><p>I started writing this game years ago, and I made a promise to myself to make it freely available. Everything you see here is the entire game (although still a work in progress), and you may feel free to play it as you see fit. The system is based on AD&amp;D 2nd Edition, but there are many changes to the mechanics. A guide has been provided at the end of this page to help you use these mechanics with your favorite old-school books.</p><p><strong>Sonata - Sword &amp; Darkness™</strong> is an Open Game License interpretation of Zeb Cook&#39;s 2nd Edition rules. All material contained within is free for use, distribution, remix, adaptation, and building upon the material in any medium or format, for noncommercial purposes only, as per the Creative Commons Attribution-NonCommercial 4.0 International license.</p></div><div class="hero-extra-text"><img src="'+r+'" class="hero-logo" alt="The three Sonata books"><h2 id="how-to-play" tabindex="-1">How to Play <a class="header-anchor" href="#how-to-play" aria-label="Permalink to &quot;How to Play&quot;">​</a></h2><p>All the content is divided throughout three books, each playing their own part. Apart from that, you will need a set of dice with d4, d6, d8, d10, d12, and d20 - the same one you use when you play any edition of Dungeons &amp; Dragons. Character sheets can be found in the <strong>Download</strong> section below.</p><ul><li><p><strong>BOOK I - CORE RULES</strong> - This book has all the mechanics you need to play - from character creation to how combat and downtime works, and so on. It&#39;s the most recommended starting point for both players and the gamesmaster.</p></li><li><p><strong>BOOK II - THE KNOWN WORLD</strong> - There are no rules covered in this book, only detailed information about the setting. Although the first book explains briefly all the ancestries and cultures of the Known World, Book II is where you learn all you need to create your own campaign.</p></li><li><p><strong>BOOK III - THE DARKNESS</strong> - This book has information more suited for the Gamesmaster, like the bestiary, rules for magic items, and more. Although players won&#39;t find any spoilers, they can skip this one if they want.</p></li></ul></div><div class="hero-extra-text"><h2 id="downloads" tabindex="-1">Downloads <a class="header-anchor" href="#downloads" aria-label="Permalink to &quot;Downloads&quot;">​</a></h2><ul><li><p><strong>Character Sheet (form-fillable)</strong> - Soon</p></li><li><p><strong>Character Sheet</strong> - <strong><a href="https://drive.google.com/file/d/18WgTT1TY1VHpWnvVvh-rF0085NvTbOUu/view?usp=drive_link" target="_blank" rel="noreferrer">LINK</a></strong></p></li><li><p><strong>Map - The Known World</strong> - <strong><a href="https://drive.google.com/file/d/1hdNkKfazIvy2SGeHYt8a4OFaxzFaHgrm/view?usp=drive_link" target="_blank" rel="noreferrer">LINK</a></strong></p></li><li><p><strong>Map - The Known World (with grids)</strong> - Soon</p></li><li><p><strong>Map - The Known World (for Foundry VTT)</strong> - Soon</p></li></ul></div><div class="hero-extra-text hero-extra-text-left"><h2 id="what-s-different" tabindex="-1">What&#39;s Different <a class="header-anchor" href="#what-s-different" aria-label="Permalink to &quot;What&#39;s Different&quot;">​</a></h2><p>Sonata - Swords &amp; Darkness runs on the <em>For Gold &amp; Glory</em> foundation, itself a retroclone of the most famous role-playing game&#39;s second edition modernized in a few specific places.</p><ul><li><strong>Attack Bonus replaces THAC0.</strong> Roll d20 + Attack Bonus against Armor Class. Same math as before, restated so higher always means better.</li><li><strong>Ascending Armor Class.</strong> Higher AC is harder to hit. A fighter in full plate has AC 19, not AC 1.</li><li><strong>Initiative is rolled every round, high roll first.</strong> Faster weapons and higher ground now push your number up instead of down.</li><li><strong>Saving throws collapse to three: Fortitude, Reflex, Will.</strong> Tied to Constitution, Dexterity, and Wisdom, and set independently from level 1 — attribute drain no longer weakens both your body and your saves at once.</li><li><strong>Non-weapon proficiencies measure quality, not permission.</strong> Anyone can cook a meal or bandage a wound. A trained character does it well.</li><li><strong>Dual-classing is gone. Multiclassing is universal.</strong> Any character can run a Primary and Secondary class side by side with no dead period, and humans get one lifetime swap of which class leads.</li></ul><h3 id="the-new-systems" tabindex="-1">The New Systems <a class="header-anchor" href="#the-new-systems" aria-label="Permalink to &quot;The New Systems&quot;">​</a></h3><ul><li><strong>Spell components shape a spell now, not gate it.</strong> Miss the material component and the casting still goes off — the potency, range, or area just drops instead.</li><li><strong>Downtime runs its own seasonal cycle.</strong> Train, study, research, craft, recover, work a faction, or run a long-term project — each one gated by resources earned during active play, so what you bring back from a dungeon decides what you can do at rest.</li><li><strong>Ancestry means something between adventures too.</strong> Every ancestry answers its own seasonal question — Badaki mark passing seasons against a hard lifespan, Húldar account for how much of themselves they still feel, Duergar and Duardeen answer to clan debts. It&#39;s mechanical weight behind the ancestry fluff, not decoration.</li></ul></div><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>If you would like to get in touch with me, feel free to shoot an email.</p><p><em><strong>Felipe Escosteguy</strong> - Sao Paulo, Brazil</em> - <a href="mailto:escosteguy.rpg@gmail.com" target="_blank" rel="noreferrer">escosteguy.rpg@gmail.com</a></p>',7)])])}const p=a(s,[["render",i]]);export{g as __pageData,p as default};
